/*
 * COMP 321 Project 4: Shell
 *
 * This program implements a tiny shell with job control.
 *
 * <Put your name(s) and NetID(s) here>
 */

#include <sys/types.h>
#include <sys/wait.h>

#include <assert.h>
#include <ctype.h>
#include <errno.h>
#include <signal.h>
#include <stdbool.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>

// You may assume that these constants are large enough.
#define MAXLINE      1024   // max line size
#define MAXARGS       128   // max args on a command line
#define MAXJOBS        16   // max jobs at any point in time
#define MAXJID   (1 << 16)  // max job ID

// The job states are:
#define UNDEF 0 // undefined
#define FG 1    // running in foreground
#define BG 2    // running in background
#define ST 3    // stopped

/*
 * The job state transitions and enabling actions are:
 *     FG -> ST  : ctrl-z
 *     ST -> FG  : fg command
 *     ST -> BG  : bg command
 *     BG -> FG  : fg command
 * At most one job can be in the FG state.
 */

struct Job {
	pid_t pid;              // job PID
	int jid;                // job ID [1, 2, ...]
	int state;              // UNDEF, FG, BG, or ST
	char cmdline[MAXLINE];  // command line
};
typedef volatile struct Job *JobP;

/*
 * Define the jobs list using the "volatile" qualifier because it is accessed
 * by a signal handler (as well as the main program).
 */
static volatile struct Job jobs[MAXJOBS];
static int nextjid = 1;            // next job ID to allocate

extern char **environ;             // defined by libc

static char prompt[] = "tsh> ";    // command line prompt (DO NOT CHANGE)
static bool verbose = false;       // If true, print additional output.

/*
 * The following array can be used to map a signal number to its name.
 * This mapping is valid for x86(-64)/Linux systems, such as CLEAR.
 * The mapping for other versions of Unix, such as FreeBSD, Mac OS X, or
 * Solaris, differ!
 */
static const char *const signame[NSIG] = {
	"Signal 0",
	"HUP",				/* SIGHUP */
	"INT",				/* SIGINT */
	"QUIT",				/* SIGQUIT */
	"ILL",				/* SIGILL */
	"TRAP",				/* SIGTRAP */
	"ABRT",				/* SIGABRT */
	"BUS",				/* SIGBUS */
	"FPE",				/* SIGFPE */
	"KILL",				/* SIGKILL */
	"USR1",				/* SIGUSR1 */
	"SEGV",				/* SIGSEGV */
	"USR2",				/* SIGUSR2 */
	"PIPE",				/* SIGPIPE */
	"ALRM",				/* SIGALRM */
	"TERM",				/* SIGTERM */
	"STKFLT",			/* SIGSTKFLT */
	"CHLD",				/* SIGCHLD */
	"CONT",				/* SIGCONT */
	"STOP",				/* SIGSTOP */
	"TSTP",				/* SIGTSTP */
	"TTIN",				/* SIGTTIN */
	"TTOU",				/* SIGTTOU */
	"URG",				/* SIGURG */
	"XCPU",				/* SIGXCPU */
	"XFSZ",				/* SIGXFSZ */
	"VTALRM",			/* SIGVTALRM */
	"PROF",				/* SIGPROF */
	"WINCH",			/* SIGWINCH */
	"IO",				/* SIGIO */
	"PWR",				/* SIGPWR */
	"Signal 31"
};

/*
 * Search path: array of directory strings parsed from PATH.
 * search_path[i] is the i-th directory; search_path_count is the count.
 * We use a static buffer to store copies of the directory strings.
 */
#define MAXPATHDIRS 256
#define MAXPATHLEN  4096

static char *search_path[MAXPATHDIRS];
static int search_path_count = 0;
static char path_buf[MAXPATHLEN];

// You must implement the following functions:

static bool	builtin_cmd(char **argv);
static void	do_bgfg(char **argv);
static void	eval(const char *cmdline);
static void	initpath(const char *pathstr);
static void	waitfg(pid_t pid);

static void	sigchld_handler(int signum);
static void	sigint_handler(int signum);
static void	sigtstp_handler(int signum);

// We are providing the following functions to you:

static bool	parseline(const char *cmdline, char **argv);

static void	sigquit_handler(int signum);

static bool	addjob(JobP jobs, pid_t pid, int state, const char *cmdline);
static void	clearjob(JobP job);
static bool	deletejob(JobP jobs, pid_t pid);
static pid_t	fgpid(JobP jobs);
static JobP	getjobjid(JobP jobs, int jid);
static JobP	getjobpid(JobP jobs, pid_t pid);
static void	initjobs(JobP jobs);
static void	listjobs(JobP jobs);
static int	maxjid(JobP jobs);
static int	pid2jid(pid_t pid);

static void	app_error(const char *msg);
static void	unix_error(const char *msg);
static void	usage(void);

static void	Sio_error(const char s[]);
static ssize_t	Sio_putl(long v);
static ssize_t	Sio_puts(const char s[]);
static void	sio_error(const char s[]);
static void	sio_ltoa(long v, char s[], int b);
static ssize_t	sio_putl(long v);
static ssize_t	sio_puts(const char s[]);
static void	sio_reverse(char s[]);
static size_t	sio_strlen(const char s[]);

/*
 * Requires:
 *   argc and argv are the standard main parameters. The shell supports
 *   -h (help), -v (verbose), and -p (no prompt) flags.
 *
 * Effects:
 *   Initializes the shell: sets up signal handlers, initializes the search
 *   path and jobs list, then runs the read/eval loop until EOF.
 */
int
main(int argc, char **argv)
{
	struct sigaction action;
	int c;
	char cmdline[MAXLINE];
	char *path = NULL;
	bool emit_prompt = true;	// Emit a prompt by default.

	/*
	 * Redirect stderr to stdout (so that driver will get all output
	 * on the pipe connected to stdout).
	 */
	if (dup2(1, 2) < 0)
		unix_error("dup2 error");

	// Parse the command line.
	while ((c = getopt(argc, argv, "hvp")) != -1) {
		switch (c) {
		case 'h':             // Print a help message.
			usage();
			break;
		case 'v':             // Emit additional diagnostic info.
			verbose = true;
			break;
		case 'p':             // Don't print a prompt.
			// This is handy for automatic testing.
			emit_prompt = false;
			break;
		default:
			usage();
		}
	}

	/*
	 * Install sigint_handler() as the handler for SIGINT (ctrl-c).
	 * Block SIGCHLD during sigint_handler to prevent interference.
	 */
	action.sa_handler = sigint_handler;
	action.sa_flags = SA_RESTART;
	if (sigemptyset(&action.sa_mask) < 0)
		unix_error("sigemptyset error");
	if (sigaddset(&action.sa_mask, SIGCHLD) < 0)
		unix_error("sigaddset error");
	if (sigaction(SIGINT, &action, NULL) < 0)
		unix_error("sigaction error");

	/*
	 * Install sigtstp_handler() as the handler for SIGTSTP (ctrl-z).
	 * Block SIGCHLD during sigtstp_handler to prevent interference.
	 */
	action.sa_handler = sigtstp_handler;
	action.sa_flags = SA_RESTART;
	if (sigemptyset(&action.sa_mask) < 0)
		unix_error("sigemptyset error");
	if (sigaddset(&action.sa_mask, SIGCHLD) < 0)
		unix_error("sigaddset error");
	if (sigaction(SIGTSTP, &action, NULL) < 0)
		unix_error("sigaction error");

	/*
	 * Install sigchld_handler() as the handler for SIGCHLD (terminated or
	 * stopped child). Block SIGINT and SIGTSTP during the handler to
	 * prevent them from interfering with job list updates.
	 */
	action.sa_handler = sigchld_handler;
	action.sa_flags = SA_RESTART;
	if (sigemptyset(&action.sa_mask) < 0)
		unix_error("sigemptyset error");
	if (sigaddset(&action.sa_mask, SIGINT) < 0)
		unix_error("sigaddset error");
	if (sigaddset(&action.sa_mask, SIGTSTP) < 0)
		unix_error("sigaddset error");
	if (sigaction(SIGCHLD, &action, NULL) < 0)
		unix_error("sigaction error");

	/*
	 * Install sigquit_handler() as the handler for SIGQUIT.  This handler
	 * provides a clean way for the test harness to terminate the shell.
	 * Preemption of the processor by the other signal handlers during
	 * sigquit_handler() does no harm, so action.sa_mask is set to empty.
	 */
	action.sa_handler = sigquit_handler;
	action.sa_flags = SA_RESTART;
	if (sigemptyset(&action.sa_mask) < 0)
		unix_error("sigemptyset error");
	if (sigaction(SIGQUIT, &action, NULL) < 0)
		unix_error("sigaction error");

	// Initialize the search path.
	path = getenv("PATH");
	initpath(path);

	// Initialize the jobs list.
	initjobs(jobs);

	// Execute the shell's read/eval loop.
	while (true) {

		// Read the command line.
		if (emit_prompt) {
			printf("%s", prompt);
			fflush(stdout);
		}
		if (fgets(cmdline, MAXLINE, stdin) == NULL && ferror(stdin))
			app_error("fgets error");
		if (feof(stdin)) // End of file (ctrl-d)
			exit(0);

		// Evaluate the command line.
		eval(cmdline);
		fflush(stdout);
	}

	// Control never reaches here.
	assert(false);
}

/*
 * eval - Evaluate the command line that the user has just typed in.
 *
 * If the user has requested a built-in command (quit, jobs, bg or fg)
 * then execute it immediately.  Otherwise, fork a child process and
 * run the job in the context of the child.  If the job is running in
 * the foreground, wait for it to terminate and then return.  Note:
 * each child process must have a unique process group ID so that our
 * background children don't receive SIGINT (SIGTSTP) from the kernel
 * when we type ctrl-c (ctrl-z) at the keyboard.
 *
 * Requires:
 *   "cmdline" is a NUL-terminated string with a trailing '\n' character,
 *   representing the command line typed by the user.
 *
 * Effects:
 *   Parses cmdline and either executes a built-in command or forks a child
 *   to run an external program. Foreground jobs are waited on; background
 *   jobs are announced and run concurrently.
 */
static void
eval(const char *cmdline)
{
	char *argv[MAXARGS];
	char buf[MAXLINE];
	bool bg;
	pid_t pid;
	sigset_t mask_chld, prev_mask;

	strcpy(buf, cmdline);
	bg = parseline(buf, argv);

	// Ignore empty command lines.
	if (argv[0] == NULL)
		return;

	// If it's a built-in command, handle it immediately.
	if (builtin_cmd(argv))
		return;

	/*
	 * Block SIGCHLD before forking to avoid the race where the child
	 * finishes and is reaped before addjob() is called.
	 */
	if (sigemptyset(&mask_chld) < 0)
		unix_error("sigemptyset error");
	if (sigaddset(&mask_chld, SIGCHLD) < 0)
		unix_error("sigaddset error");
	if (sigprocmask(SIG_BLOCK, &mask_chld, &prev_mask) < 0)
		unix_error("sigprocmask error");

	if ((pid = fork()) < 0)
		unix_error("fork error");

	if (pid == 0) {
		/* Child process */

		/* Put the child in a new process group so ctrl-c/z only
		 * affects the shell's foreground process group, not ours. */
		if (setpgid(0, 0) < 0)
			unix_error("setpgid error");

		/* Unblock SIGCHLD in the child. */
		if (sigprocmask(SIG_SETMASK, &prev_mask, NULL) < 0)
			unix_error("sigprocmask error");

		/* Determine the program to execute. */
		if (strchr(argv[0], '/') != NULL || search_path_count == 0) {
			/* argv[0] contains a directory component, or no PATH:
			 * treat it as a path name directly. */
			if (execve(argv[0], argv, environ) < 0) {
				printf("%s: Command not found\n", argv[0]);
				exit(1);
			}
		} else {
			/* Search PATH directories for the executable. */
			int i;
			char fullpath[MAXLINE];
			bool found = false;

			for (i = 0; i < search_path_count; i++) {
				if (search_path[i][0] == '\0') {
					/* Empty string means current directory. */
					snprintf(fullpath, sizeof(fullpath),
					    "./%s", argv[0]);
				} else {
					snprintf(fullpath, sizeof(fullpath),
					    "%s/%s", search_path[i], argv[0]);
				}
				if (execve(fullpath, argv, environ) >= 0) {
					found = true;
					break;
				}
				/* execve only returns on failure; keep trying. */
			}
			if (!found) {
				printf("%s: Command not found\n", argv[0]);
				exit(1);
			}
		}
	}

	/* Parent process */

	/* Add the job to the job list before unblocking SIGCHLD. */
	if (!addjob(jobs, pid, bg ? BG : FG, cmdline))
		unix_error("addjob error");

	/* Unblock SIGCHLD. */
	if (sigprocmask(SIG_SETMASK, &prev_mask, NULL) < 0)
		unix_error("sigprocmask error");

	if (bg) {
		/* Background job: print announcement. */
		printf("[%d] (%d) %s", pid2jid(pid), (int)pid, cmdline);
	} else {
		/* Foreground job: wait for it to finish. */
		waitfg(pid);
	}
}

/*
 * parseline - Parse the command line and build the argv array.
 *
 * Requires:
 *   "cmdline" is a NUL ('\0') terminated string with a trailing
 *   '\n' character.  "cmdline" must contain less than MAXARGS
 *   arguments.
 *
 * Effects:
 *   Builds "argv" array from space delimited arguments on the command line.
 *   The final element of "argv" is set to NULL.  Characters enclosed in
 *   single quotes are treated as a single argument.  Returns true if
 *   the user has requested a BG job and false if the user has requested
 *   a FG job.
 *
 * Note:
 *   In the textbook, this function has the return type "int", but "bool"
 *   is more appropriate.
 */
static bool
parseline(const char *cmdline, char **argv)
{
	int argc;                   // number of args
	static char array[MAXLINE]; // local copy of command line
	char *buf = array;          // ptr that traverses command line
	char *delim;                // points to first space delimiter
	bool bg;                    // background job?

	strcpy(buf, cmdline);

	// Replace trailing '\n' with space.
	buf[strlen(buf) - 1] = ' ';

	// Ignore leading spaces.
	while (*buf != '\0' && *buf == ' ')
		buf++;

	// Build the argv list.
	argc = 0;
	if (*buf == '\'') {
		buf++;
		delim = strchr(buf, '\'');
	} else
		delim = strchr(buf, ' ');
	while (delim != NULL) {
		argv[argc++] = buf;
		*delim = '\0';
		buf = delim + 1;
		while (*buf != '\0' && *buf == ' ')	// Ignore spaces.
			buf++;
		if (*buf == '\'') {
			buf++;
			delim = strchr(buf, '\'');
		} else
			delim = strchr(buf, ' ');
	}
	argv[argc] = NULL;

	// Ignore blank line.
	if (argc == 0)
		return (true);

	// Should the job run in the background?
	if ((bg = (*argv[argc - 1] == '&')) != 0)
		argv[--argc] = NULL;

	return (bg);
}

/*
 * builtin_cmd - If the user has typed a built-in command then execute
 *  it immediately.
 *
 * Requires:
 *   "argv" is a NULL-terminated array of strings representing the command
 *   and its arguments.
 *
 * Effects:
 *   If argv[0] is a built-in command (quit, jobs, bg, fg), executes it and
 *   returns true. Otherwise returns false.
 *
 * Note:
 *   In the textbook, this function has the return type "int", but "bool"
 *   is more appropriate.
 */
static bool
builtin_cmd(char **argv)
{
	if (strcmp(argv[0], "quit") == 0) {
		exit(0);
	} else if (strcmp(argv[0], "jobs") == 0) {
		listjobs(jobs);
		return (true);
	} else if (strcmp(argv[0], "bg") == 0 ||
	           strcmp(argv[0], "fg") == 0) {
		do_bgfg(argv);
		return (true);
	}
	return (false);     // This is not a built-in command.
}

/*
 * do_bgfg - Execute the built-in bg and fg commands.
 *
 * Requires:
 *   "argv" is a NULL-terminated array where argv[0] is "bg" or "fg" and
 *   argv[1] is a job specifier (either a PID like "1234" or a JID like "%5").
 *
 * Effects:
 *   Sends SIGCONT to the specified job and changes its state to BG or FG.
 *   If fg, waits for the job to finish. Prints appropriate error messages
 *   for invalid arguments or non-existent jobs.
 */
static void
do_bgfg(char **argv)
{
	JobP job;
	int jid;
	pid_t pid;
	char *arg;

	if (argv[1] == NULL) {
		printf("%s command requires PID or %%jobid argument\n", argv[0]);
		return;
	}

	arg = argv[1];

	if (arg[0] == '%') {
		/* JID argument */
		char *endptr;
		jid = (int)strtol(arg + 1, &endptr, 10);
		if (*endptr != '\0' || endptr == arg + 1) {
			printf("%s: argument must be a PID or %%jobid\n",
			    argv[0]);
			return;
		}
		job = getjobjid(jobs, jid);
		if (job == NULL) {
			printf("%%%d: No such job\n", jid);
			return;
		}
	} else {
		/* PID argument */
		char *endptr;
		long pidl = strtol(arg, &endptr, 10);
		if (*endptr != '\0' || endptr == arg) {
			printf("%s: argument must be a PID or %%jobid\n",
			    argv[0]);
			return;
		}
		pid = (pid_t)pidl;
		job = getjobpid(jobs, pid);
		if (job == NULL) {
			printf("(%d): No such process\n", (int)pid);
			return;
		}
	}

	/* Send SIGCONT to the job's process group. */
	if (kill(-(job->pid), SIGCONT) < 0)
		unix_error("kill error");

	if (strcmp(argv[0], "bg") == 0) {
		job->state = BG;
		printf("[%d] (%d) %s", job->jid, (int)job->pid, job->cmdline);
	} else {
		/* fg: bring to foreground and wait. */
		pid_t fg_pid = job->pid;
		job->state = FG;
		waitfg(fg_pid);
	}
}

/*
 * waitfg - Block until process pid is no longer the foreground process.
 *
 * Requires:
 *   "pid" is the PID of the current foreground job.
 *
 * Effects:
 *   Suspends the shell using sigsuspend until the foreground job is no
 *   longer in the FG state (it has terminated or been stopped).
 */
static void
waitfg(pid_t pid)
{
	sigset_t mask;

	if (sigemptyset(&mask) < 0)
		unix_error("sigemptyset error");

	/*
	 * Loop while the job is still the foreground job.
	 * sigsuspend atomically unblocks all signals and suspends the
	 * process until a signal is caught, then re-blocks them.
	 * Since we call this with no signals blocked (the caller has
	 * already unblocked SIGCHLD), we pass an empty mask to allow
	 * all signals during the suspend.
	 */
	while (fgpid(jobs) == pid)
		sigsuspend(&mask);
}

/*
 * initpath - Perform all necessary initialization of the search path,
 *  which may be simply saving the path.
 *
 * Requires:
 *   "pathstr" is a valid search path string (colon-separated directories),
 *   or NULL if PATH is not set.
 *
 * Effects:
 *   Parses pathstr and stores the directories in search_path[]. Sets
 *   search_path_count to the number of directories found.
 */
static void
initpath(const char *pathstr)
{
	char *p, *tok;

	search_path_count = 0;

	if (pathstr == NULL)
		return;

	/* Copy the path string into our buffer so we can tokenize it. */
	strncpy(path_buf, pathstr, sizeof(path_buf) - 1);
	path_buf[sizeof(path_buf) - 1] = '\0';

	/*
	 * Split on ':'. strsep handles empty tokens (consecutive colons,
	 * or leading/trailing colons) correctly by returning an empty string.
	 */
	p = path_buf;
	while ((tok = strsep(&p, ":")) != NULL) {
		if (search_path_count >= MAXPATHDIRS)
			break;
		search_path[search_path_count++] = tok;
	}
}

